// ── Conversation Persistence (localStorage) ──────────────────────────────
// Tab-isolated conversation key (CX-P2-04) — each tab gets its own storage slot
const _TAB_ID = (() => {
  let id = sessionStorage.getItem("cx_tab_id");
  if (!id) { id = `t${Date.now().toString(36)}`; try { sessionStorage.setItem("cx_tab_id", id); } catch { /* ignore */ } }
  return id;
})();
const CONV_STORAGE_KEY = `crossx_conv_v2_${_TAB_ID}`;
const CONV_STORAGE_KEY_SHARED = "crossx_conv_v2"; // legacy / cross-tab shared (read-only for restore)
const CONV_TTL_MS = 30 * 24 * 60 * 60 * 1000; // 30 days

function saveConversationState() {
  try {
    const toSave = {
      messages: (state.agentConversation.messages || []).slice(-20),
      slots: { ...state.agentConversation.slots },
      savedAt: Date.now(),
    };
    localStorage.setItem(CONV_STORAGE_KEY, JSON.stringify(toSave));
  } catch { /* quota exceeded or storage disabled — ignore */ }
}

function restoreConversationState() {
  try {
    // Only restore tab-scoped conversation. The legacy shared key polluted fresh tabs
    // with unrelated old requests, which then corrupted follow-up planning state.
    const raw = localStorage.getItem(CONV_STORAGE_KEY);
    if (!raw) return;
    const saved = JSON.parse(raw);
    if (!saved || !saved.savedAt) return;
    if (Date.now() - saved.savedAt > CONV_TTL_MS) {
      localStorage.removeItem(CONV_STORAGE_KEY);
      return;
    }
    if (Array.isArray(saved.messages) && saved.messages.length > 0) {
      // Keep restored turns out of active prompt history until the user
      // explicitly continues. Hidden restored turns were contaminating fresh
      // requests while the UI only showed a compact banner.
      state._restoredConversation = {
        messages: saved.messages.slice(-20),
        savedAt: saved.savedAt,
      };
      state._sessionRestored = true;
      state._restoredAt = saved.savedAt;
    }
    if (saved.slots && typeof saved.slots === "object") {
      Object.assign(state.agentConversation.slots, saved.slots);
    }
  } catch { /* corrupt data — ignore */ }
}

