function escapeHtml(input) {
  return String(input || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function inlineJsArg(value) {
  return escapeHtml(JSON.stringify(value));
}

function assetUrl(url) {
  const raw = String(url || "");
  if (!raw) return "";
  if (/^https?:\/\//i.test(raw)) return raw;
  return `${raw}${raw.includes("?") ? "&" : "?"}v=${ASSET_VERSION}`;
}

function tTerm(key) {
  return i18n.term(state.uiLanguage, key);
}

function tUi(key, vars) {
  return i18n.t(state.uiLanguage, `ui.${key}`, vars);
}

function pickText(zh, en, ja, ko, id, ar) {
  if (state.uiLanguage === "ZH" || state.uiLanguage === "ZH-TW") return zh;
  if (state.uiLanguage === "JA") return ja || en;
  if (state.uiLanguage === "KO") return ko || en;
  if (state.uiLanguage === "ID") return id || en;
  if (state.uiLanguage === "AR") return ar || en;
  return en;
}

function isUiFallbackLanguage(language = state.uiLanguage) {
  return UI_FALLBACK_LANGUAGES.has(String(language || "").toUpperCase());
}

function getUiFallbackNotice(language = state.uiLanguage) {
  const lang = String(language || "").toUpperCase();
  if (!isUiFallbackLanguage(lang)) return "";
  const label = UI_FALLBACK_LANGUAGE_LABELS[lang] || lang;
  return pickText(
    `${label} 目前为英文界面降级模式，Booking/Agoda 链接会尽量使用对应语言参数。`,
    `${label} is currently in English fallback mode. Booking/Agoda links will use localized language parameters when available.`,
    `${label} は現在英語UIでのフォールバック表示です。Booking/Agoda リンクは可能な範囲で該当言語パラメータを使います。`,
    `${label} UI는 현재 영어 폴백 모드입니다. Booking/Agoda 링크에는 가능한 경우 해당 언어 파라미터를 적용합니다。`,
    `${label} saat ini memakai fallback UI bahasa Inggris. Tautan Booking/Agoda akan memakai parameter bahasa bila tersedia.`,
    `تعمل ${label} حالياً بواجهة إنجليزية احتياطية. وستستخدم روابط Booking/Agoda معلمات اللغة المناسبة عند توفرها.`,
  );
}

function getEffectiveUiLanguage(language = state.uiLanguage) {
  const lang = String(language || state.uiLanguage || "EN").toUpperCase();
  if (lang === "ZH-CN") return "ZH";
  if (lang === "ZH-HK" || lang === "ZH-MO") return "ZH-TW";
  return lang || "EN";
}

function getLocalizedPrivacyUrl(language = state.uiLanguage) {
  const lang = getEffectiveUiLanguage(language);
  const pageLang =
    lang === "ZH" ? "zh"
    : lang === "ZH-TW" ? "zh-TW"
    : lang === "JA" ? "ja"
    : lang === "KO" ? "ko"
    : lang === "ID" ? "id"
    : lang === "AR" ? "ar"
    : "en";
  return `/privacy?lang=${encodeURIComponent(pageLang)}`;
}

function syncPrivacyLinkTargets(scope = document, language = state.uiLanguage) {
  if (!scope || typeof scope.querySelectorAll !== "function") return;
  const href = getLocalizedPrivacyUrl(language);
  scope.querySelectorAll('a[href="/privacy"], a[href^="/privacy?"], a[data-privacy-link="1"]').forEach((node) => {
    node.setAttribute("href", href);
  });
}

function setButtonVisibleText(button, text) {
  if (!button) return;
  const labelNode = button.querySelector?.('[data-button-label="1"]');
  if (labelNode) labelNode.textContent = text;
  else button.textContent = text;
  button.setAttribute("aria-label", text);
}

function formatThinkingCharCount(count) {
  const safeCount = Number(count) || 0;
  if (safeCount <= 0) return "";
  return pickText(
    `${safeCount} 字`,
    `${safeCount} chars`,
    `${safeCount} 文字`,
    `${safeCount}자`,
    `${safeCount} karakter`,
    `${safeCount} حرفًا`,
  );
}

function shouldSummarizeThinkingForCurrentLanguage(text) {
  const lang = getEffectiveUiLanguage();
  if (lang === "ZH" || lang === "ZH-TW") return false;
  return String(text || "").trim().length > 0;
}

function normalizeThinkingStatusText(text, fallback = "") {
  const raw = String(text || "").trim();
  if (!raw) return fallback;
  const localized = _localizeVisibleTravelText(raw, fallback, state.uiLanguage);
  return localized || fallback || raw;
}

function buildAgentMessageExportHtml(text) {
  const now = new Date();
  const title = pickText("CrossX AI 回复导出", "CrossX AI Response Export", "CrossX AI返信エクスポート", "CrossX AI 응답 내보내기");
  const body = escapeHtml(String(text || "")).replace(/\n/g, "<br>");
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${escapeHtml(title)}</title>
  <style>
    :root { color-scheme: light; }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      font-family: "SF Pro Text", "Segoe UI", "Noto Sans", sans-serif;
      background: linear-gradient(180deg, #f6f3ee 0%, #ffffff 100%);
      color: #1f2937;
    }
    .wrap {
      max-width: 880px;
      margin: 0 auto;
      padding: 40px 24px 64px;
    }
    .toolbar {
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
      margin-bottom: 20px;
    }
    .btn {
      border: 0;
      border-radius: 999px;
      padding: 11px 18px;
      font: inherit;
      cursor: pointer;
      background: #111827;
      color: #fff;
    }
    .btn.secondary {
      background: #e5e7eb;
      color: #111827;
    }
    .card {
      background: rgba(255,255,255,0.92);
      border: 1px solid rgba(17,24,39,0.08);
      border-radius: 24px;
      padding: 28px;
      box-shadow: 0 18px 50px rgba(15,23,42,0.08);
    }
    h1 {
      margin: 0 0 8px;
      font-size: 28px;
      line-height: 1.1;
    }
    .meta {
      color: #6b7280;
      font-size: 14px;
      margin-bottom: 20px;
    }
    .message {
      font-size: 16px;
      line-height: 1.8;
      white-space: normal;
      word-break: break-word;
    }
    @media print {
      body { background: #fff; }
      .toolbar { display: none; }
      .wrap { max-width: none; padding: 0; }
      .card {
        box-shadow: none;
        border: 0;
        border-radius: 0;
        padding: 0;
      }
    }
  </style>
</head>
<body>
  <div class="wrap">
    <div class="toolbar">
      <button class="btn" id="cxExportPrintBtn">${escapeHtml(pickText("保存为 PDF", "Save as PDF", "PDFとして保存", "PDF로 저장"))}</button>
      <button class="btn secondary" id="cxExportCopyBtn">${escapeHtml(pickText("复制文本", "Copy text", "テキストをコピー", "텍스트 복사"))}</button>
    </div>
    <article class="card">
      <h1>${escapeHtml(title)}</h1>
      <div class="meta">${escapeHtml(now.toLocaleString())}</div>
      <div class="message">${body}</div>
    </article>
  </div>
</body>
</html>`;
}

function exportAgentMessageAsPdf(text) {
  const popup = window.open("", "_blank", "noopener,noreferrer,width=960,height=760");
  if (!popup) {
    notify(
      pickText("导出窗口被浏览器拦截，请允许弹窗后重试。", "The export window was blocked by your browser. Allow pop-ups and try again.", "エクスポート画面がブロックされました。ポップアップを許可して再試行してください。", "내보내기 창이 차단되었습니다. 팝업을 허용한 뒤 다시 시도해 주세요."),
      "warning",
    );
    return false;
  }
  popup.document.documentElement.innerHTML = buildAgentMessageExportHtml(text);
  const printBtn = popup.document.getElementById("cxExportPrintBtn");
  const copyBtn = popup.document.getElementById("cxExportCopyBtn");
  if (printBtn) {
    printBtn.addEventListener("click", () => {
      try { popup.print(); } catch {}
    });
  }
  if (copyBtn) {
    copyBtn.addEventListener("click", async () => {
      try {
        if (!popup.navigator?.clipboard?.writeText) throw new Error("clipboard_unavailable");
        await popup.navigator.clipboard.writeText(popup.document.body.innerText);
      } catch {}
    });
  }
  popup.focus();
  setTimeout(() => {
    try { popup.print(); } catch {}
  }, 250);
  return true;
}

function getLoopStages() {
  return [
    { key: "intent", label: pickText("意图", "Intent", "意図", "의도") },
    { key: "plan", label: pickText("计划", "Plan", "計画", "계획") },
    { key: "confirm", label: pickText("确认", "Confirm", "確認", "확인") },
    { key: "execute", label: pickText("执行", "Execute", "実行", "실행") },
    { key: "proof", label: pickText("凭证", "Proof", "証憑", "증빙") },
    { key: "support", label: pickText("售后", "Support", "サポート", "지원") },
  ];
}

function getLoopStageIndex(key) {
  const stages = getLoopStages();
  const idx = stages.findIndex((item) => item.key === key);
  return idx < 0 ? 0 : idx;
}

function renderFlowRail() {
  if (!el.flowRail) return;
  const stages = getLoopStages();
  const activeIndex = getLoopStageIndex(state.loopProgress || "intent");
  el.flowRail.innerHTML = stages
    .map((stage, idx) => {
      const phase = idx < activeIndex ? "done" : idx === activeIndex ? "active" : "pending";
      return `
        <div class="flow-step ${phase}" data-stage="${escapeHtml(stage.key)}">
          <span class="flow-dot" aria-hidden="true"></span>
          <span class="flow-label">${escapeHtml(stage.label)}</span>
        </div>
      `;
    })
    .join("");
}

function setLoopProgress(stageKey) {
  const safe = stageKey || "intent";
  state.loopProgress = safe;
  renderFlowRail();
  renderConversationAura();
  renderHumanAssistDock();
}

function getConversationAuraState() {
  if (state.voice.listening) {
    return { mode: "listening", label: pickText("正在聆听，你可以直接说需求。", "Listening. Speak your request.", "聞き取り中です。要望を話してください。", "듣는 중입니다. 요청을 말해 주세요.") };
  }
  if (state.voice.speaking) {
    return { mode: "speaking", label: pickText("正在播报方案与下一步动作。", "Speaking the plan and next action.", "プランと次のアクションを読み上げ中です。", "계획과 다음 행동을 안내 중입니다.") };
  }
  if (state.voice.processing) {
    return { mode: "planning", label: pickText("正在理解你的意图并组装执行方案。", "Understanding intent and assembling plan.", "意図を解析して実行プランを構成中です。", "의도를 파악하고 실행 계획을 구성 중입니다.") };
  }
  if (state.loopProgress === "execute" || state.loopProgress === "proof") {
    return { mode: "executing", label: pickText("正在执行步骤并生成凭证。", "Executing steps and generating proof.", "ステップを実行して証憑を生成中です。", "단계를 실행하고 증빙을 생성 중입니다.") };
  }
  if (state.loopProgress === "plan" || state.loopProgress === "confirm") {
    return { mode: "planning", label: pickText("正在规划可执行闭环。", "Planning executable closed loop.", "実行可能なクローズドループを計画中です。", "실행 가능한 폐쇄 루프를 계획 중입니다.") };
  }
  if (state.loopProgress === "support") {
    return { mode: "support", label: pickText("已进入人工协助流程，系统持续跟进。", "Human assist mode active. Monitoring in progress.", "有人サポートに切替済み。継続監視中です。", "사람 지원 모드 활성. 계속 모니터링 중입니다.") };
  }
  return { mode: "idle", label: pickText("待命中。输入一句话即可开始闭环执行。", "Standby. One sentence starts execution.", "待機中。ひと言で実行を開始できます。", "대기 중. 한 문장으로 실행을 시작할 수 있습니다.") };
}

function renderConversationAura() {
  if (!el.conversationAura) return;
  const meta = getConversationAuraState();
  el.conversationAura.dataset.mode = meta.mode;
  if (el.conversationAuraLabel) {
    el.conversationAuraLabel.textContent = meta.label;
  }
}

function pulseConversationAura() {
  if (!el.conversationAura) return;
  el.conversationAura.classList.remove("aura-burst");
  void el.conversationAura.offsetWidth;
  el.conversationAura.classList.add("aura-burst");
}

let thinkingActivatedAt = 0;
let thinkingHideTimer = null;
// P2: abort controller for in-flight plan stream (one active stream at a time)
let _currentPlanAbortController = null;
// FS-B-02: Abort controller for in-flight /api/chat/reply calls — prevents duplicate submissions
let _activeChatReplyCtrl = null;

// ── Smart auto-scroll ────────────────────────────────────────────────────────
// Pause when user manually scrolls up; resume when back near bottom.
let _chatScrollPaused = false;
let _chatScrollListenerTarget = null;
function _getChatScrollContainer(feed) {
  if (_isMobileConversationMode() && document.body?.classList.contains("single-dialog-mode")) {
    return el.chat?.isConnected
      ? el.chat
      : document.getElementById("chatTab")
        || el.taskWorkspace
        || document.getElementById("taskWorkspace")
        || feed
        || el.chatFeed
        || document.getElementById("chatFeed");
  }
  return el.taskWorkspace || document.getElementById("taskWorkspace") || feed || el.chatFeed || document.getElementById("chatFeed");
}
function _measureScrollDistance(container) {
  if (!container) return 0;
  return Math.max(0, container.scrollHeight - container.scrollTop - container.clientHeight);
}
function _isCompactMobileViewport() {
  return typeof window !== "undefined" && window.innerWidth <= 768;
}
function _isMobileConversationMode() {
  return _isCompactMobileViewport() && document.body?.classList.contains("consumer-app");
}
function _applyCompactTopbarContract() {
  if (!document.body?.classList.contains("consumer-app")) return;
  const compact = _isCompactMobileViewport();
  const loginBtn = document.getElementById("loginBtn");
  const locateBtn = document.getElementById("locateBtn");
  const locationTag = document.getElementById("locationTag");
  const userNameTag = document.getElementById("userNameTag");
  const logoutBtn = document.getElementById("logoutBtn");
  if (locateBtn) {
    locateBtn.hidden = false;
    locateBtn.classList.remove("hidden");
    locateBtn.style.display = compact ? "inline-flex" : "";
  }
  if (!compact) {
    [locationTag, userNameTag, logoutBtn, loginBtn].forEach((node) => {
      if (node) {
        node.hidden = false;
        node.style.display = "";
      }
    });
    if (locationTag) {
      if (String(locationTag.textContent || "").trim()) locationTag.classList.remove("hidden");
      else locationTag.classList.add("hidden");
    }
    const loggedIn = Boolean(loginBtn && loginBtn.classList.contains("hidden"));
    if (userNameTag) userNameTag.classList.toggle("hidden", !loggedIn);
    if (logoutBtn) logoutBtn.classList.toggle("hidden", !loggedIn);
    return;
  }
  if (locationTag) {
    locationTag.hidden = true;
    locationTag.classList.add("hidden");
    locationTag.style.display = "none";
  }
  if (userNameTag) {
    userNameTag.hidden = true;
    userNameTag.classList.add("hidden");
    userNameTag.style.display = "none";
  }
  if (logoutBtn) {
    logoutBtn.hidden = true;
    logoutBtn.classList.add("hidden");
    logoutBtn.style.display = "none";
  }
  if (loginBtn && !loginBtn.classList.contains("hidden")) loginBtn.style.display = "";
}
function _shouldForceOutputFocus() {
  return _isMobileConversationMode() && (
    state._planStreamActive === true ||
    state.agentConversation?.smartLoading === true ||
    document.body?.classList.contains("cx-cold-start")
  );
}
function _focusComposerAfterReply() {
  if (!_isMobileConversationMode() || document.getElementById("cx-login-modal")) return;
  if (!el.chatInput || typeof el.chatInput.focus !== "function") return;
  window.requestAnimationFrame(() => {
    try {
      el.chatInput.focus({ preventScroll: true });
    } catch {
      el.chatInput.focus();
    }
  });
}
function _smartScrollToBottom(feed, options = {}) {
  const container = _getChatScrollContainer(feed);
  if (!container) return;
  if (_chatScrollListenerTarget !== container) {
    _chatScrollListenerTarget = container;
    container.addEventListener("scroll", () => {
      _chatScrollPaused = _measureScrollDistance(container) > 80;
    }, { passive: true });
  }
  if (_chatScrollPaused && options.force !== true) return;
  container.scrollTop = container.scrollHeight;
}
function _revealConversationNode(node, options = {}) {
  if (!node) return;
  const force = options.force === true;
  if (_chatScrollPaused && !force) return;
  if (_isMobileConversationMode() && typeof node.scrollIntoView === "function") {
    node.scrollIntoView({
      behavior: options.behavior || (force ? "smooth" : "auto"),
      block: options.block || "nearest",
      inline: "nearest",
    });
    return;
  }
  _smartScrollToBottom(el.chatFeed, { force });
}
function _isPrimaryResultCard(node) {
  return Boolean(
    node &&
    node.matches &&
    node.matches(".plan-card, .plan-card--v2, .cx-td-card, .task-panel, .task-status-card, .cx-pb-card, .smart-reply-card")
  );
}

// ── Tool-call context skeleton ───────────────────────────────────────────────
let _toolSkeletonEl = null;
const _TOOL_SKEL_META = {
  search_hotels:       { icon: "🏨", label: (d) => pickText(`搜索${d}酒店中...`, `Finding ${d} hotels...`, `${d}のホテルを検索中...`, `${d} 호텔 검색 중...`) },
  search_restaurants:  { icon: "🍜", label: (d) => pickText(`搜索${d}餐厅中...`, `Finding ${d} restaurants...`, `${d}のレストランを検索中...`, `${d} 식당 검색 중...`) },
  get_attractions:     { icon: "🗺️", label: (d) => pickText(`搜索${d}景点中...`, `Finding ${d} attractions...`, `${d}の観光地を検索中...`, `${d} 명소 검색 중...`) },
  get_route_options:   { icon: "🚄", label: ()  => pickText("计算路线中...",    "Calculating routes...",     "ルート計算中...",           "경로 계산 중...") },
  get_city_enrichment: { icon: "✨", label: (d) => pickText(`丰富${d}数据中...`, `Enriching ${d} data...`,    `${d}のデータを充実化中...`, `${d} 데이터 보강 중...`) },
};
function _showToolSkeleton(toolName, dest) {
  if (_toolSkeletonEl) return; // only one at a time
  const feed = document.getElementById("chatFeed");
  if (!feed) return;
  const meta = _TOOL_SKEL_META[toolName] || { icon: "⚙️", label: () => pickText("AI 搜索中...", "AI searching...", "AI 検索中...", "AI 검색 중...") };
  const label = meta.label(dest || "");
  const row = document.createElement("div");
  row.className = "msg agent";
  row.innerHTML = `<span class="bubble cx-tool-skel-bubble">` +
    `<span class="cx-tool-skel-icon">${meta.icon}</span>` +
    `<span class="cx-tool-skel-lines">` +
    `<span class="cx-tool-skel-line"></span>` +
    `<span class="cx-tool-skel-line"></span>` +
    `<span class="cx-tool-skel-line"></span>` +
    `<span class="cx-tool-skel-label">${label}</span>` +
    `</span></span>`;
  feed.appendChild(row);
  motion.enter(row, { duration: 160, fromY: 6 });
  _smartScrollToBottom(feed);
  _toolSkeletonEl = row;
}
function _removeToolSkeleton() {
  if (!_toolSkeletonEl) return;
  const row = _toolSkeletonEl;
  _toolSkeletonEl = null;
  row.classList.add("cx-fadeout");
  setTimeout(() => { if (row.parentElement) row.remove(); }, 250);
}

/**
 * isAiBusy() — true whenever ANY async AI operation is in flight.
 * Language switching must never trigger new LLM calls while busy.
 * Covers: SSE plan stream, slot-filling, chat reply, thinking indicator.
 */
function isAiBusy() {
  return Boolean(_currentPlanAbortController)
      || Boolean(_activeChatReplyCtrl)
      || el.thinkingIndicator?.classList.contains("is-active") === true;
}

function applyThinkingIndicatorState(active, text = "") {
  if (!el.thinkingIndicator) return;
  const on = active === true;
  el.thinkingIndicator.classList.toggle("hidden", !on);
  el.thinkingIndicator.classList.toggle("is-active", on);
  // Apple AI animation: glow border on chat form + background aura
  if (el.chatForm) el.chatForm.classList.toggle("is-ai-thinking", on);
  document.body.classList.toggle("ai-thinking", on);
  if (on) {
    el.thinkingIndicator.textContent =
      text
      || pickText(
        "正在为你规划...",
        "Planning your trip...",
        "プランを作成中...",
        "여행 계획 중...",
        "Merencanakan perjalanan...",
      );
    if (el.conversationAura) {
      el.conversationAura.dataset.mode = "planning";
    }
    pulseConversationAura();
  } else {
    renderConversationAura();
  }
}

function setThinkingIndicator(active, text = "") {
  const on = active === true;
  if (on) {
    if (thinkingHideTimer) {
      clearTimeout(thinkingHideTimer);
      thinkingHideTimer = null;
    }
    thinkingActivatedAt = Date.now();
    applyThinkingIndicatorState(true, text);
  } else {
    const elapsed = Date.now() - thinkingActivatedAt;
    const delay = Math.max(0, 420 - elapsed);
    if (delay > 0) {
      if (thinkingHideTimer) clearTimeout(thinkingHideTimer);
      thinkingHideTimer = setTimeout(() => {
        thinkingHideTimer = null;
        applyThinkingIndicatorState(false);
      }, delay);
      return;
    }
    applyThinkingIndicatorState(false);
  }
}

function renderHumanAssistDock() {
  if (!el.humanAssistSummary || !el.humanAssistMode) return;
  const task = state.currentTask || null;
  // Only show the Human Assist card when there's an active task or open tickets
  if (el.humanAssistCard) {
    const tickets = Array.isArray(state.supportTickets) ? state.supportTickets : [];
    const hasOpenTicket = tickets.some((t) => ["open","in_progress"].includes(String(t.status||"").toLowerCase()));
    el.humanAssistCard.classList.toggle("hidden", !(task || hasOpenTicket));
  }
  const tickets = Array.isArray(state.supportTickets) ? state.supportTickets : [];
  const openTickets = tickets.filter((t) => ["open", "in_progress"].includes(String(t.status || "").toLowerCase()));
  const currentTicketId = task && task.handoff ? String(task.handoff.ticketId || "") : "";
  const currentTicket = currentTicketId ? tickets.find((t) => t.id === currentTicketId) || null : null;

  let modeKey = "standby";
  if (currentTicket && String(currentTicket.status || "") === "resolved") modeKey = "resolved";
  else if (currentTicket || state.loopProgress === "support") modeKey = "active";
  else if (openTickets.length > 0) modeKey = "watching";

  const modeLabel =
    modeKey === "resolved"
      ? pickText("已解决", "Resolved", "解決済み", "해결됨")
      : modeKey === "active"
        ? pickText("人工处理中", "Human Active", "有人対応中", "사람 처리중")
        : modeKey === "watching"
          ? pickText("监督中", "Watching", "監視中", "모니터링")
          : pickText("待命", "Standby", "待機", "대기");
  const badgeClass = modeKey === "resolved" ? "success" : modeKey === "active" ? "running" : "queued";
  el.humanAssistMode.className = `status-badge ${badgeClass}`;
  el.humanAssistMode.textContent = modeLabel;

  if (task) {
    el.humanAssistSummary.textContent = pickText(
      `当前任务 ${task.id} 可由人工监督并接管关键步骤。`,
      `Task ${task.id} can be supervised with human takeover on critical steps.`,
      `現在のタスク ${task.id} は重要ステップで有人監督・引継ぎが可能です。`,
      `현재 작업 ${task.id} 은(는) 핵심 단계에서 사람 감독/인계가 가능합니다.`,
    );
  } else {
    el.humanAssistSummary.textContent = pickText(
      "当前没有活动任务，建议先输入目标再决定是否转人工。",
      "No active task. Start with one goal, then escalate to human if needed.",
      "進行中タスクはありません。まず目標を入力し、必要時に有人へ切替してください。",
      "활성 작업이 없습니다. 목표를 입력한 뒤 필요 시 사람 지원으로 전환하세요.",
    );
  }

  if (currentTicket) {
    const ticketLine = pickText(
      `工单 ${currentTicket.id} · 状态 ${localizeStatus(currentTicket.status)}`,
      `Ticket ${currentTicket.id} · ${localizeStatus(currentTicket.status)}`,
      `チケット ${currentTicket.id} · ${localizeStatus(currentTicket.status)}`,
      `티켓 ${currentTicket.id} · ${localizeStatus(currentTicket.status)}`,
    );
    el.humanAssistTicket.innerHTML = `
      <span>${escapeHtml(ticketLine)}</span>
      <button class="secondary" data-action="open-ticket-detail" data-ticket="${escapeHtml(currentTicket.id)}">${pickText("查看详情", "Open Detail", "詳細を見る", "상세 보기")}</button>
      <button class="secondary" data-action="open-live-support" data-ticket="${escapeHtml(currentTicket.id)}">${pickText("进入人工会话", "Open Live Room", "ライブ会話を開く", "실시간 상담 열기")}</button>
    `;
    if (el.humanAssistEta) {
      el.humanAssistEta.dataset.createdAt = String(currentTicket.createdAt || currentTicket.updatedAt || new Date().toISOString());
      el.humanAssistEta.dataset.etaMin = String(Number(currentTicket.etaMin || 0));
      el.humanAssistEta.classList.add("eta-live");
    }
  } else {
    el.humanAssistTicket.textContent = pickText(
      `当前开放工单 ${openTickets.length} 个。`,
      `${openTickets.length} open support ticket(s) in queue.`,
      `オープンチケット ${openTickets.length} 件。`,
      `열린 지원 티켓 ${openTickets.length}건.`,
    );
    if (el.humanAssistEta) {
      el.humanAssistEta.textContent = "";
      delete el.humanAssistEta.dataset.createdAt;
      delete el.humanAssistEta.dataset.etaMin;
      el.humanAssistEta.classList.remove("eta-live");
    }
  }

  const recent = tickets
    .slice()
    .sort((a, b) => String(b.updatedAt || b.createdAt || "").localeCompare(String(a.updatedAt || a.createdAt || "")))
    .slice(0, 3)
    .map(
      (ticket) =>
        `<li><strong>${escapeHtml(ticket.id)}</strong> · <span class="status-badge ${escapeHtml(ticket.status || "queued")}">${escapeHtml(localizeStatus(ticket.status || "open"))}</span> <span class="status">${new Date(ticket.updatedAt || ticket.createdAt).toLocaleString()}</span></li>`,
    )
    .join("");
  if (el.humanAssistRecent) {
    el.humanAssistRecent.innerHTML =
      recent || `<li>${pickText("暂无人工工单记录。", "No human assist ticket yet.", "有人チケットはまだありません。", "사람 지원 티켓이 아직 없습니다.")}</li>`;
  }

  if (el.assistRequestBtn) {
    if (task && task.id) {
      el.assistRequestBtn.removeAttribute("disabled");
      el.assistRequestBtn.dataset.task = task.id;
    } else {
      el.assistRequestBtn.setAttribute("disabled", "true");
      delete el.assistRequestBtn.dataset.task;
    }
    if (currentTicket && ["open", "in_progress"].includes(String(currentTicket.status || "").toLowerCase())) {
      el.assistRequestBtn.textContent = pickText("人工已接管", "Human already assigned", "有人対応中", "사람 상담 진행중");
    } else {
      el.assistRequestBtn.textContent = pickText("请求人工监督", "Request Human Supervision", "有人監督を依頼", "사람 감독 요청");
    }
  }
  if (el.assistLiveCallBtn) {
    const preferred = currentTicket || openTickets[0] || null;
    if (preferred) {
      el.assistLiveCallBtn.removeAttribute("disabled");
      el.assistLiveCallBtn.dataset.ticket = preferred.id;
    } else {
      el.assistLiveCallBtn.setAttribute("disabled", "true");
      delete el.assistLiveCallBtn.dataset.ticket;
    }
  }
  updateSupportEtaCountdown();
}

function applySingleDialogMode() {
  if (IS_USER_PORTAL) {
    state.viewMode = "user";
    state.singleDialogMode = true;
  }
  if (state.viewMode !== "admin") {
    state.singleDialogMode = true;
  }
  document.body.classList.toggle("single-dialog-mode", state.singleDialogMode === true);
  // Show/hide admin-only workspace panels (Context, FlowRail, AgentBrain)
  const _isWorkspace = state.viewMode === "admin" && !state.singleDialogMode;
  document.querySelectorAll(".admin-workspace-only").forEach((el) => {
    el.classList.toggle("hidden", !_isWorkspace);
  });
  if (state.singleDialogMode) {
    switchTab("chat", { force: true });
  }
  if (el.workspaceModeBtn) {
    const lockUserMode = state.viewMode !== "admin";
    const label = state.singleDialogMode
      ? pickText("切换工作台", "Open Workspace", "ワークスペース表示", "워크스페이스 열기")
      : pickText("简化对话", "Simple Dialog", "シンプル会話", "단순 대화");
    el.workspaceModeBtn.textContent = label;
    el.workspaceModeBtn.setAttribute("aria-pressed", state.singleDialogMode ? "true" : "false");
    el.workspaceModeBtn.title = state.singleDialogMode
      ? pickText("当前为单对话模式", "Single-dialog mode enabled", "シングル会話モード有効", "단일 대화 모드 활성")
      : pickText("当前为工作台模式", "Workspace mode enabled", "ワークスペースモード有効", "워크스페이스 모드 활성");
    el.workspaceModeBtn.classList.toggle("hidden-by-mode", lockUserMode);
    if (lockUserMode) {
      el.workspaceModeBtn.setAttribute("disabled", "true");
    } else {
      el.workspaceModeBtn.removeAttribute("disabled");
    }
  }
  autoResizeChatInput();
  _syncColdStartLayout();
}

function shouldPreferConciergeHome() {
  return false;
}

function getPrimaryTripSummary() {
  const trips = Array.isArray(state.tripPlans) ? state.tripPlans : [];
  if (!trips.length) return null;
  return (
    trips.find((trip) => trip.id === state.activeTripId)
    || trips.find((trip) => ["active", "in_progress"].includes(String(trip.status || "").toLowerCase()))
    || trips[0]
  );
}

function getConciergeGreeting() {
  const hour = new Date().getHours();
  if (hour < 11) return pickText("早上好", "Good morning", "おはようございます", "좋은 아침입니다");
  if (hour < 18) return pickText("下午好", "Good afternoon", "こんにちは", "좋은 오후입니다");
  return pickText("晚上好", "Good evening", "こんばんは", "좋은 저녁입니다");
}

function formatHomeAmount(order) {
  if (!order) return pickText("待确认", "Pending", "未確定", "확인 대기");
  const amount = Number(order.totalPrice || order.amount || order.price || 0);
  const currency = String(order.currency || "CNY");
  if (currency === "CNY") return formatCNY(amount);
  return `${amount.toLocaleString()} ${currency}`;
}

function getOrderTitle(order) {
  if (!order) return pickText("订单", "Order", "注文", "주문");
  return _localizeVisibleTravelText(order.displayLabel || order.provider || order.merchant || order.type || "", pickText("订单", "Order", "注文", "주문"));
}

