      <a href="${escapeHtml(getLocalizedPrivacyUrl())}" target="_blank" rel="noopener" data-privacy-link="1">${pickText("查看隐私政策", "Read Privacy Policy", "プライバシーポリシーを見る", "개인정보 처리방침 보기")}</a>
