          <button class="secondary" data-action="retry-step" data-task="${escapeHtml(detail.overview.taskId)}" data-step="${escapeHtml(s.id)}">${pickText("重试这一步", "Retry this step","このステップを再試行", "이 단계 재시도")}</button>
